appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const summary = rawData.components?.summary || {};
    const byProvider = summary.by_provider || {};
    const byType = summary.by_type || {};

    // =====================================================================
    // CONFIG — presentation/category constants only. Every count below is
    // read from the scan; the exposure index uses NO weighting coefficients.
    // =====================================================================
    const CONFIG = {
      indexCap: 100,
      indexThresholds: {
        high: 75,
        medium: 40
      },
      indexColors: {
        high: '#c0392b',
        medium: '#f39c12',
        low: '#27ae60'
      },
      serializationTypes: ['Pickle', 'Joblib', 'H5', 'PT', 'Safetensors'],
      categoryLabels: {
        serialization: 'Serialization Format',
        vendor: 'AI Vendor / Tooling',
        various: 'Mixed Ecosystem'
      },
      // Honest, factual integrity statements (no invented "Verified" claim):
      integrity: {
        serialization: {
          text: 'Unsigned artifact format',
          badge: 'badge-critical'
        },
        other: {
          text: 'External provider / API',
          badge: 'badge-neutral',
          box: 'border:1px solid #5dade2;background:#eaf4fb;color:#1b4f72;border-radius:3px;'
        }
      },
      // Risk weight derived from the serialization category (a real property),
      // not from any single hardcoded provider name.
      weight: {
        high: {
          text: 'High Exposure',
          badge: 'badge-critical'
        },
        standard: {
          text: 'Standard',
          badge: 'badge-neutral',
          box: 'border:1px solid #58d68d;background:#eafaf1;color:#1e8449;border-radius:3px;'
        }
      },
      emptyTable: 'No providers detected.'
    };

    // --- 1. Taxonomy + counts (all from the scan) -----------------------
    const processedEntities = Object.entries(byProvider).map(([name, count]) => {
      const isSerialization = CONFIG.serializationTypes.includes(name);
      let category = isSerialization ? CONFIG.categoryLabels.serialization : CONFIG.categoryLabels.vendor;
      if (name === 'Various') category = CONFIG.categoryLabels.various;
      return {
        name,
        count,
        category,
        isSerialization
      };
    });

    // Active vendors: providers that are neither serialization formats nor "Various".
    const activeVendorCount = processedEntities.filter(e => !e.isSerialization && e.name !== 'Various').length;

    // Dominant artifact + total artifacts come from the authoritative
    // by_type.model_artifact bucket (NOT by_provider, which conflates code refs).
    const artProviders = byType.model_artifact?.providers || {};
    let dominantArtifact = 'None';
    let maxArtifactCount = 0;
    Object.entries(artProviders).forEach(([name, files]) => {
      const n = Array.isArray(files) ? files.length : files;
      if (n > maxArtifactCount) {
        maxArtifactCount = n;
        dominantArtifact = name;
      }
    });
    const artifactCount = byType.model_artifact?.count || 0;

    // --- 2. AI Boundary Exposure Index (raw, unweighted sum) ------------
    const boundaryCrossings = rawData.cross_file?.ai_boundaries || 0;
    const undeclaredComponents = (byType.llm_framework?.count || 0) + (byType.agent?.count || 0);
    const eligibilityViolations = rawData.crossings?.prohibited_count || 0;

    // No coefficients: each factor contributes its own count, so the breakdown
    // below always reconciles with the displayed score.
    const factors = [['Boundaries', boundaryCrossings], ['Vendors', activeVendorCount], ['Frameworks', undeclaredComponents], ['Artifacts', artifactCount], ['Violations', eligibilityViolations]];
    const rawScore = factors.reduce((sum, [, v]) => sum + v, 0);
    const indexScore = Math.min(CONFIG.indexCap, rawScore);

    // --- Update KPI cards + explanation ---------------------------------
    document.getElementById('dominant-artifact').innerText = dominantArtifact;
    document.getElementById('active-vendors').innerText = activeVendorCount;
    document.getElementById('exposure-index').innerText = `${indexScore}/${CONFIG.indexCap}`;
    const indexEl = document.getElementById('exposure-index');
    if (indexScore > CONFIG.indexThresholds.high) indexEl.style.color = CONFIG.indexColors.high;else if (indexScore > CONFIG.indexThresholds.medium) indexEl.style.color = CONFIG.indexColors.medium;else indexEl.style.color = CONFIG.indexColors.low;
    const breakdown = factors.map(([k, v]) => `${v} ${v === 1 ? 'pt' : 'pts'} (${k})`).join(', ');
    const capNote = rawScore > CONFIG.indexCap ? ` (raw ${rawScore}, capped at ${CONFIG.indexCap})` : '';
    document.getElementById('index-explanation').innerText = `Score factors: ${breakdown}.${capNote}`;

    // --- 3. Provider & Artifact Distribution table ----------------------
    const tbody = document.getElementById('taxonomy-table-body');
    tbody.innerHTML = '';
    if (processedEntities.length === 0) {
      tbody.innerHTML = `<tr><td colspan="5" style="text-align: center;">${CONFIG.emptyTable}</td></tr>`;
      return;
    }

    // Serialization formats first, then by descending count.
    processedEntities.sort((a, b) => b.isSerialization - a.isSerialization || b.count - a.count).forEach(entity => {
      const tr = document.createElement('tr');
      const tdName = document.createElement('td');
      const strong = document.createElement('strong');
      strong.textContent = entity.name;
      tdName.appendChild(strong);
      const tdCat = document.createElement('td');
      tdCat.textContent = entity.category;
      const tdCount = document.createElement('td');
      tdCount.textContent = entity.count;

      // Integrity status (factual, derived from category)
      const tdIntegrity = document.createElement('td');
      const integrity = entity.isSerialization ? CONFIG.integrity.serialization : CONFIG.integrity.other;
      const integrityBadge = document.createElement('span');
      integrityBadge.className = `badge ${integrity.badge}`;
      integrityBadge.textContent = integrity.text;
      if (integrity.box) integrityBadge.style.cssText = integrity.box;
      tdIntegrity.appendChild(integrityBadge);

      // Risk weight (derived from serialization category — no per-name rules)
      const tdWeight = document.createElement('td');
      const weight = entity.isSerialization ? CONFIG.weight.high : CONFIG.weight.standard;
      const weightBadge = document.createElement('span');
      weightBadge.className = `badge ${weight.badge}`;
      weightBadge.textContent = weight.text;
      if (weight.box) weightBadge.style.cssText = weight.box;
      tdWeight.appendChild(weightBadge);
      tr.appendChild(tdName);
      tr.appendChild(tdCat);
      tr.appendChild(tdCount);
      tr.appendChild(tdIntegrity);
      tr.appendChild(tdWeight);
      tbody.appendChild(tr);
    });
  });
});

